mapper.select:
SELECT TA.SEQ, TA.NAME, TA.SORTING , TA.CREATE_IDX, CUSER.NAME AS CREATE_USER_NAME, TA.CREATE_DATETIME , TA.UPDATE_IDX, UUSER.NAME AS UPDATE_USER_NAME, TA.UPDATE_DATETIME FROM TB_AUTH AS TA LEFT OUTER JOIN TB_USER AS CUSER ON CUSER.SEQ = TA.CREATE_IDX LEFT OUTER JOIN TB_USER AS UUSER ON UUSER.SEQ = TA.UPDATE_IDX WHERE 1 = 1 AND TA.DELETED = 0
AND TA.NAME LIKE CONCAT('%', #{searchValue}, '%')
ORDER BY TA.SORTING, TA.SEQ LIMIT #{startDataNumber}, #{dataCount}

mapper.update:
UPDATE TB_AUTH
SET UPDATE_IDX = #{createIdx},
    UPDATE_DATETIME = NOW(),

    NAME = #{name},


    SORTING = #{sorting}

WHERE SEQ = #{seq}
